#include <bits/stdc++.h>
using namespace std;
long long gcd(long long a,long long b){
	if(a%b==0){
		return b;
	}
	return gcd(b,a%b);
}
int main(){
	long long n,m;
	cin>>n>>m;
	long long a[n];
	for(int i=0;i<n;i++){
		cin>>a[i];
	}
	long long b,k=1;
	for(int i=0;i<m;i++){
		b=a[0]+k;
		for(int j=1;j<n;j++){
			b=gcd(b,a[j]+k);
			if(b==1){
				break;
			}
		}
		k++;
		cout<<b<<endl;
	}
	return 0;

}
